parameters.jsCode:
const whisper = $input.first().json;
const webhook = $("Webhook Entrada").first().json.body;

const t = whisper.text || '';
const m2 = webhook.m2 || 20;
const feria = webhook.feria || 'No detectada';
const cliente = webhook.cliente || 'Sin especificar';

return [{ json: {
  chatInput: [
    'SOLICITUD DE PRESUPUESTO (desde audio/voz)',
    '---',
    'Cliente: ' + cliente,
    'Feria: ' + feria,
    'Superficie: ' + m2 + ' m²',
    'Presupuesto máximo: ' + (webhook.presupuesto_max ? webhook.presupuesto_max + '€' : 'No indicado'),
    'Transcripción completa: ' + t,
    '---',
    'Usa consultar_tarifa_base_a primero, luego genera el presupuesto completo.'
  ].join('\n')
}}];

// ═══════════════════════════════════════════════════════════
// CONSTRUIR CONTEXTO RAG — combina los 3 resultados de Qdrant
// ═══════════════════════════════════════════════════════════

const proyectos = $('HTTP: Qdrant Proyectos').first().json.result || [];
const catalogo  = $('HTTP: Qdrant Catálogo B').first().json.result || [];
const guias     = $('HTTP: Qdrant Guías').first().json.result || [];

// chatInput original: viene del nodo que se ejecutó en esta rama
let chatInputOriginal = '';
try { chatInputOriginal = $('Formatear Mensaje - Imagen').first().json.chatInput || ''; } catch(e) {}
try { if (!chatInputOriginal) chatInputOriginal = $('Formatear Mensaje - Audio').first().json.chatInput || ''; } catch(e) {}
try { if (!chatInputOriginal) chatInputOriginal = $('Edit Fields - Formatear Texto').first().json.chatInput || ''; } catch(e) {}

let contexto = '';

// ── PROYECTOS HISTÓRICOS ──────────────────────────────────
if (proyectos.length > 0) {
  contexto += '\n\n=== PROYECTOS HISTÓRICOS SIMILARES (RAG) ===\n';
  contexto += 'Úsalos como referencia de precio total y enfoque de diseño:\n';
  proyectos.forEach(p => {
    const pay = p.payload;
    const score = (p.score * 100).toFixed(0);
    contexto += `- [${score}% similitud] ${pay.codigo_proyecto || 'Proyecto'}: `;
    contexto += `${pay.nombre_feria || ''}, ${pay.tipo_stand || ''}, ${pay.m2 || ''}m², `;
    contexto += `nivel ${pay.nivel_densidad || ''}, estilo ${pay.estilo || ''}, `;
    contexto += `TOTAL: ${pay.total_presupuesto || ''}€`;
    if (pay.margen_real_porcentaje && pay.margen_real_porcentaje > 0) {
      contexto += `, margen real: ${pay.margen_real_porcentaje}%`;
    }
    contexto += '\n';
  });
} else {
  contexto += '\n\n=== PROYECTOS HISTÓRICOS: Sin resultados similares encontrados ===\n';
}

// ── CATÁLOGO B (elementos con precio) ───────────────────
if (catalogo.length > 0) {
  contexto += '\n=== ELEMENTOS CATÁLOGO B RELEVANTES (RAG) ===\n';
  contexto += 'Usa estos precios directamente en las partidas 1-5:\n';
  catalogo.forEach(c => {
    const pay = c.payload;
    const score = (c.score * 100).toFixed(0);
    const sku   = pay.codigo_sku || '';
    const nombre = pay.nombre_elemento || pay.content?.substring(0, 60) || '';
    const precio = pay.precio_venta_unidad || '';
    const unidad = pay.unidad_medida_bloque || 'ud';
    const desc   = pay.descripcion_comercial ? pay.descripcion_comercial.substring(0, 100) : '';
    contexto += `- [${score}%] [${sku}] ${nombre}: ${precio}€/${unidad}`;
    if (desc) contexto += ` — ${desc}`;
    contexto += '\n';
  });
} else {
  contexto += '\n=== CATÁLOGO B: Sin elementos relevantes encontrados ===\n';
}

// ── GUÍAS Y REGLAS TÉCNICAS ──────────────────────────────
if (guias.length > 0) {
  contexto += '\n=== GUÍAS Y REGLAS TÉCNICAS APLICABLES (RAG) ===\n';
  guias.forEach(g => {
    const pay = g.payload;
    const score = (g.score * 100).toFixed(0);
    const texto = pay.content || '';
    const fuente = pay.metadata?.file_name || 'guia';
    if (texto) {
      contexto += `- [${score}%] (${fuente}): ${texto.substring(0, 350)}\n`;
    }
  });
}

// ── ENRIQUECER chatInput ──────────────────────────────────
const bloque = contexto
  ? '\n\n━━━ CONTEXTO RAG PRE-CARGADO (usa como referencia obligatoria) ━━━' + contexto + '━━━ FIN CONTEXTO RAG ━━━'
  : '';

const chatInputFinal = chatInputOriginal + bloque;

return [{ json: { chatInput: chatInputFinal } }];

const vision = $input.first().json;
const webhook = $("Webhook Entrada").first().json.body;

let p = {};
try {
  const raw = vision.choices[0].message.content;
  p = JSON.parse(raw.replace(/```json|```/g, '').trim());
} catch(e) {
  p = {};
}

const output = {
  tipo_stand: p.tipo_stand || webhook.tipo_stand || "modular",
  estilo: p.estilo || webhook.estilo || "moderno",
  materiales_visibles: p.materiales_visibles || [],
  elementos_destacados: p.elementos_destacados || [],
  m2_estimado: p.m2_estimado || null,
  altura_estimada: p.altura_estimada || null,
  numero_frentes: p.numero_frentes || 1,
  densidad: p.densidad || "media",
  tiene_grafica: p.tiene_grafica ?? false,
  tipo_iluminacion: p.tipo_iluminacion || "no_detectado",
  colores: p.colores || [],
  descripcion: p.descripcion || "",
  m2_real: webhook.m2 || null,
  feria: webhook.feria || "No especificada",
  cliente: webhook.cliente || "Sin especificar",
  promptText: webhook.promptText || "",
};

return [{ json: output }];
